def guard(features: dict, prediction: str) -> str:
    """Skip trades against OBV volume flow direction."""
    obv_slope = features.get('obv_slope', 0)

    # Skip long positions when OBV shows distribution (negative slope)
    if prediction == "long" and obv_slope < -0.01:
        return "skip"

    # Skip short positions when OBV shows accumulation (positive slope)
    if prediction == "short" and obv_slope > 0.01:
        return "skip"

    return prediction
